const express = require('express');
const db = require('../db');
const router = express.Router();

// VULNERABLE: Direct string concatenation
router.get('/search', async (req, res) => {
  try {
    const query = req.query.q;
    const sortBy = req.query.sort || 'name';

    // SQL INJECTION VULNERABILITY: query is directly concatenated
    const sql = `SELECT id, name, email FROM users WHERE name LIKE '%${query}%' ORDER BY ${sortBy}`;
    const result = await db.query(sql);

    res.json(result.rows);
  } catch (error) {
    res.status(500).json({ error: error.message });
  }
});

// VULNERABLE: Filter injection
router.get('/filter', async (req, res) => {
  try {
    const filter = req.query.filter; // e.g., "status='active'"

    // SQL INJECTION VULNERABILITY: filter is directly concatenated
    const sql = `SELECT * FROM users WHERE ${filter}`;
    const result = await db.query(sql);

    res.json(result.rows);
  } catch (error) {
    res.status(500).json({ error: error.message });
  }
});

// VULNERABLE: Email update without parameterization
router.post('/update-email', async (req, res) => {
  try {
    const userId = req.body.id;
    const newEmail = req.body.email;

    // SQL INJECTION VULNERABILITY: Values not parameterized
    const sql = `UPDATE users SET email = '${newEmail}' WHERE id = ${userId}`;
    await db.query(sql);

    res.json({ success: true });
  } catch (error) {
    res.status(500).json({ error: error.message });
  }
});

// VULNERABLE: CSV export with unsanitized column names
router.get('/export', async (req, res) => {
  try {
    const columns = req.query.columns.split(',');

    // SQL INJECTION VULNERABILITY: Column names not validated
    const columnList = columns.join(', ');
    const sql = `SELECT ${columnList} FROM users`;
    const result = await db.query(sql);

    res.json(result.rows);
  } catch (error) {
    res.status(500).json({ error: error.message });
  }
});

// VULNERABLE: Login bypass
router.post('/login', async (req, res) => {
  try {
    const username = req.body.username;
    const password = req.body.password;

    // SQL INJECTION VULNERABILITY: No parameterization, allows login bypass
    // Example attack: username = "admin' --" bypasses password check
    const sql = `SELECT id, role FROM users WHERE username = '${username}' AND password = '${password}'`;
    const result = await db.query(sql);

    if (result.rows.length > 0) {
      res.json({ success: true, role: result.rows[0].role });
    } else {
      res.status(401).json({ error: 'Invalid credentials' });
    }
  } catch (error) {
    res.status(500).json({ error: error.message });
  }
});

module.exports = router;

